368→/**
369→ * Wrap an existing provider with the oblivious proof overlay.
370→ *
371→ * This is the primary integration function for getRpcProvider.ts:
372→ *
373→ *   let provider = createProvider(config)   // helios, colibri, or rpc
374→ *   if (config.obliviousProofServerUrl) {
375→ *     provider = wrapWithOblivious(provider, config.chainId, {
376→ *       proofServerUrl: config.obliviousProofServerUrl,
377→ *     })
378→ *   }
379→ */
380→export function wrapWithOblivious(
381→  inner: JsonRpcProvider,
382→  chainId: bigint | number,
383→  options: ObliviousOverlayOptions
384→): ObliviousProofOverlay {
385→  return new ObliviousProofOverlay(inner, chainId, options);
386→}
387→
388→/**
389→ * Chains supported by oblivious_node.
390→ */
391→export function isObliviousSupportedChain(chainId?: bigint | number): boolean {
392→  if (!chainId) return false;
393→  const supported = [1, 11155111]; // mainnet + sepolia
394→  return supported.includes(Number(chainId));
395→}
